// ============================================
// TIMESTAMP SNAPPING - Corrects AI's approximate timestamps
// to precise word boundaries from the transcript
// ============================================

// Get the word timestamps from the "Get Word Timestamps" node
const wordTimestampsRaw = $('Get Word Timestamps').first().json.data;

// Parse the word timestamps (they come as a string representation of Python objects)
let segments;
try {
  // The data might be a string that looks like Python repr
  // We need to convert np.float64() to regular numbers
  let cleaned = wordTimestampsRaw
    .replace(/np\.float64\(([^)]+)\)/g, '$1')
    .replace(/'/g, '"')
    .replace(/True/g, 'true')
    .replace(/False/g, 'false')
    .replace(/None/g, 'null');

  segments = JSON.parse(cleaned);
} catch (e) {
  // If already an object, use directly
  segments = wordTimestampsRaw;
}

// Flatten all words from all segments into a single array
const allWords = [];
for (const segment of segments) {
  if (segment.words) {
    for (const word of segment.words) {
      allWords.push({
        word: word.word.trim(),
        start: parseFloat(word.start),
        end: parseFloat(word.end)
      });
    }
  }
}

console.log(`Total words extracted: ${allWords.length}`);

// Helper function to convert "HH:MM:SS" or "MM:SS" to seconds
function timeToSeconds(timeStr) {
  if (typeof timeStr === 'number') return timeStr;
  const parts = timeStr.split(':').map(Number);
  if (parts.length === 3) {
    return parts[0] * 3600 + parts[1] * 60 + parts[2];
  } else if (parts.length === 2) {
    return parts[0] * 60 + parts[1];
  }
  return parseFloat(timeStr);
}

// Helper function to convert seconds to "HH:MM:SS" format
function secondsToTime(seconds) {
  const hrs = Math.floor(seconds / 3600);
  const mins = Math.floor((seconds % 3600) / 60);
  const secs = Math.floor(seconds % 60);
  return `${String(hrs).padStart(2, '0')}:${String(mins).padStart(2, '0')}:${String(secs).padStart(2, '0')}`;
}

// Function to find the nearest word boundary
function findNearestWordBoundary(targetSeconds, boundaryType = 'start') {
  let bestWord = null;
  let bestDiff = Infinity;

  for (const word of allWords) {
    const wordTime = boundaryType === 'start' ? word.start : word.end;
    const diff = Math.abs(wordTime - targetSeconds);

    if (diff < bestDiff) {
      bestDiff = diff;
      bestWord = word;
    }
  }

  return bestWord;
}

// Get the AI-generated clips from the input
let aiClips = [];
for (const item of $input.all()) {
  if (item.json.clips) {
    aiClips = aiClips.concat(item.json.clips);
  } else if (item.json.timeStart || item.json.start_time) {
    aiClips.push(item.json);
  }
}

// If no clips in input, try to get from Limit Clips2 node
if (aiClips.length === 0) {
  try {
    const limitClips = $('Limit Clips2').all();
    for (const item of limitClips) {
      if (item.json.clips) {
        aiClips = aiClips.concat(item.json.clips);
      } else {
        aiClips.push(item.json);
      }
    }
  } catch (e) {
    console.log('Limit Clips2 node not found, trying alternatives...');
  }
}

console.log(`Found ${aiClips.length} clips to process`);

// Process each clip and snap its timestamps
const correctedClips = [];

for (const clip of aiClips) {
  const originalStart = clip.timeStart || clip.start_time || clip.startTime;
  const originalEnd = clip.timeEnd || clip.end_time || clip.endTime;

  if (!originalStart || !originalEnd) {
    correctedClips.push(clip);
    continue;
  }

  const startSeconds = timeToSeconds(originalStart);
  const endSeconds = timeToSeconds(originalEnd);

  // Find nearest word boundaries
  const startWord = findNearestWordBoundary(startSeconds, 'start');
  const endWord = findNearestWordBoundary(endSeconds, 'end');

  // Create corrected clip
  const correctedClip = {
    ...clip,
    // Original timestamps
    originalTimeStart: originalStart,
    originalTimeEnd: originalEnd,
    // Corrected timestamps (in seconds)
    timeStartSeconds: startWord ? startWord.start : startSeconds,
    timeEndSeconds: endWord ? endWord.end : endSeconds,
    // Corrected timestamps (formatted)
    timeStart: startWord ? secondsToTime(startWord.start) : originalStart,
    timeEnd: endWord ? secondsToTime(endWord.end) : originalEnd,
    // Additional info
    startWord: startWord ? startWord.word : null,
    endWord: endWord ? endWord.word : null,
    // Duration
    durationSeconds: (endWord ? endWord.end : endSeconds) - (startWord ? startWord.start : startSeconds)
  };

  console.log(`Clip: ${originalStart} -> ${correctedClip.timeStart}, ${originalEnd} -> ${correctedClip.timeEnd}`);

  correctedClips.push(correctedClip);
}

// Return the corrected clips
return correctedClips.map(clip => ({ json: clip }));

// Calculate FFmpeg crop filter based on face detection
const clip = $input.first().json;

// Get video dimensions from metadata
const videoWidth = $('Get Metadata').first().json.response.width || 1920;
const videoHeight = $('Get Metadata').first().json.response.height || 1080;

// Get clip dimensions (9:16 vertical)
const clipWidth = parseInt($('On form submission').first().json['Clip Size'].split('x')[0]) || 1080;
const clipHeight = parseInt($('On form submission').first().json['Clip Size'].split('x')[1]) || 1920;

// Face detection results
const faceData = clip;

let cropX = 0;
let cropY = 0;
let cropWidth = clipWidth;
let cropHeight = clipHeight;

if (faceData && faceData.face_detected) {
  // Calculate crop centered on face
  const faceCenterX = faceData.center_x_pixels;
  const faceCenterY = faceData.center_y_pixels;

  // For vertical video, we typically crop width to maintain 9:16
  // Calculate the crop width needed to achieve the aspect ratio
  const targetAspectRatio = clipWidth / clipHeight; // 9:16 = 0.5625

  // Crop width based on full height
  cropHeight = videoHeight;
  cropWidth = Math.round(cropHeight * targetAspectRatio);

  // Center crop on face X position
  cropX = Math.max(0, Math.min(videoWidth - cropWidth, faceCenterX - cropWidth / 2));
  cropY = 0; // Start from top for vertical video

  // If crop width exceeds video width, adjust
  if (cropWidth > videoWidth) {
    cropWidth = videoWidth;
    cropHeight = Math.round(cropWidth / targetAspectRatio);
    cropY = Math.max(0, Math.min(videoHeight - cropHeight, faceCenterY - cropHeight / 2));
  }
} else {
  // No face detected, center crop
  const targetAspectRatio = clipWidth / clipHeight;
  cropHeight = videoHeight;
  cropWidth = Math.round(cropHeight * targetAspectRatio);
  cropX = Math.round((videoWidth - cropWidth) / 2);
  cropY = 0;
}

// Round all values to integers
cropX = Math.round(cropX);
cropY = Math.round(cropY);
cropWidth = Math.round(cropWidth);
cropHeight = Math.round(cropHeight);

// Generate FFmpeg crop filter
const cropFilter = `crop=${cropWidth}:${cropHeight}:${cropX}:${cropY}`;

return {
  json: {
    ...clip,
    // Crop configuration
    cropFilter: cropFilter,
    cropX: cropX,
    cropY: cropY,
    cropWidth: cropWidth,
    cropHeight: cropHeight,
    // Video info
    originalWidth: videoWidth,
    originalHeight: videoHeight,
    targetWidth: clipWidth,
    targetHeight: clipHeight
  }
};
